def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(8, 2, -1):
                for b in range(1, a + 5):
                    base = np.tanh((ratio - a) ** 4 / (b * 1.1 + 1))
                    angle = (ratio * b) / (a + 0.7)
                    priority += base * np.sin(angle) * np.exp(-0.05 * i)
            priority += (np.cosh(ratio - 7) * np.sin(0.9 * ratio)) ** 1.8
            if i % 2 == 0:
                priority += np.log1p(bin_cap) * 3.3
            else:
                priority -= np.sqrt(ratio) * 4.1
        elif 5 < ratio <= 8:
            for c in range(1, int(ratio) + 5):
                for d in range(1, c + 4):
                    val = ((ratio - c) ** 2.5) * np.cos(ratio * d) / (d + 0.8)
                    priority += np.tanh(val) * 2.1
            priority += np.log(ratio + 1) * 12 - np.tanh(ratio - 5) * 2.8
            if bin_cap < item * 0.95:
                priority += np.exp(-(bin_cap / (item + 0.1))) * 5
            else:
                priority -= np.sin(ratio * 2.2) * 3
        elif 2 <= ratio <= 5:
            s = 0
            for e in range(1, 15):
                s += (((ratio - 2) ** e) / (e * 2.1)) * np.cos(e * ratio * 1.2)
            priority = s * np.cos(6.5 * ratio) - np.log(ratio) * 5.5 + np.tanh(3 * (5 - ratio)) * 2.5
            for f in range(1, 7):
                priority += np.sin(f * ratio * i) * ((ratio - 1.8) ** f) / (f * 0.8)
        elif 1 <= ratio < 2:
            s = 0
            for g in range(1, 20):
                denom = np.sqrt(g ** 3 + 1)
                s += ((2 - ratio) ** g) / denom * np.cos(g * ratio * 0.7)
            if bin_cap < item * 1.05:
                penalty = np.log1p(item * ratio) * 3.7
            else:
                penalty = np.cos(15 * ratio) * 3.1
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for h in range(1, 6):
                priority += np.sin(h * ratio * i * 0.9) * ((ratio - 1) ** h) / (h + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for j in range(1, 18):
                s += ((1 - ratio) ** j) / (j * 3) * np.sin(j * item * 1.3)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.7)
            for k in range(1, 7):
                priority += ((1 - ratio) ** k) * np.cos(k * item * 0.9) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for l in range(1, 14):
                s += ((0.5 - ratio) ** l) / (l * 4.5) * np.cos(l * ratio * 2.5)
            priority = s + 0.4 / (bin_cap + 2)
            if int(item * 1.7) % 3 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 3.8
            else:
                priority -= np.exp(-ratio * 1.5) * 5
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 5) * np.sin(item * m * 1.2)
        else:
            s = 0
            for n in range(1, 12):
                s += ((0.2 - ratio) ** n) / (n * 6) * np.cos(n * item * 1.1)
            priority = s + 1.5 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 3) * 6
            for o in range(1, 11):
                priority += ((0.2 - ratio) ** o) / (o * 8) * np.sin(item * o * 0.7)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for p in range(1, 5):
            if (i + p) % 4 == 0:
                priority += np.sin(ratio * (i + p) * 1.3) * 0.4
            else:
                priority -= np.cos(ratio * (i + p) * 1.3) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.15) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.15) * 0.7
        priorities[i] = priority
    return priorities
